const serviceItems = $('Service List').all();
const resultItems = items;
const results = [];
let allOk = true;

for (let i = 0; i < serviceItems.length; i++) {
  const service = serviceItems[i].json;
  const result = resultItems[i]?.json || {};

  const isDown = result.error !== undefined && result.error !== null || result.statusCode !== 200 && result.statusCode !== 302 && result.statusCode !== 204 && result.statusCode !== 301;
  const errorMsg = isDown ? (result.error?.message || result.error || `HTTP ${result.statusCode || 'Failed'}`) : null;

  if (isDown) allOk = false;

  results.push({
    name: service.name,
    url: service.url,
    status: isDown ? "DOWN" : "ONLINE",
    error: errorMsg
  });
}

return [{
  json: {
    services: results,
    all_ok: allOk
  }
}];

const stdout = items[0].json.stdout || "";
const lines = stdout.split("\n");

const expectedContainers = {
  "automation-01": [
    "netdata",
    "portainer",
    "uptime-kuma",
    "homepage",
    "watchtower",
    "nginx-proxy-manager",
    "n8n",
    "life-control-center",
    "semaphore",
    "forgejo"
  ],
  "docker-01": [
    "netdata",
    "portainer_agent",
    "dozzle",
    "watchtower",
    "cloudflared",
    "nextcloud-app",
    "nextcloud-redis",
    "nextcloud-db"
  ],
  "colmado-db": [
    "supabase-db",
    "supabase-storage",
    "supabase-meta",
    "supabase-studio",
    "supabase-pooler",
    "realtime-dev.supabase-realtime",
    "supabase-auth",
    "supabase-edge-functions",
    "supabase-kong",
    "supabase-rest",
    "supabase-analytics",
    "supabase-vector",
    "supabase-imgproxy"
  ]
};

const running = {
  "automation-01": {},
  "docker-01": {},
  "colmado-db": {}
};

const hostOffline = {
  "automation-01": false,
  "docker-01": false,
  "colmado-db": false
};

const diskUsage = {
  "automation-01": null,
  "docker-01": null,
  "colmado-db": null
};

let parsingSection = "";
let currentDiskHost = "";

for (const rawLine of lines) {
  const line = rawLine.trim();
  if (!line) continue;

  if (line.includes("=== DOCKER STATUS ===")) {
    parsingSection = "DOCKER";
    continue;
  }
  if (line.includes("=== DISK USAGE ===")) {
    parsingSection = "DISK";
    continue;
  }

  if (parsingSection === "DOCKER") {
    const parts = line.split("|");
    if (parts.length >= 2) {
      const host = parts[0].trim();
      const containerName = parts[1].trim();
      if (containerName === "OFFLINE") {
        hostOffline[host] = true;
      } else if (parts.length >= 3) {
        const status = parts[2].trim();
        running[host][containerName] = status;
      }
    }
  } else if (parsingSection === "DISK") {
    if (line.startsWith("=== ") && line.endsWith(" ===")) {
      currentDiskHost = line.replace(/===/g, "").trim();
      continue;
    }

    if (currentDiskHost) {
      if (line === "OFFLINE") {
        diskUsage[currentDiskHost] = "OFFLINE";
      } else {
        const parts = line.split(/\s+/);
        if (parts.length >= 6 && parts[5] === "/") {
          diskUsage[currentDiskHost] = {
            size: parts[1],
            used: parts[2],
            available: parts[3],
            usage: parts[4]
          };
        }
      }
    }
  }
}

const containersSummary = {};
let allContainersOk = true;

for (const host of ["automation-01", "docker-01", "colmado-db"]) {
  if (hostOffline[host]) {
    containersSummary[host] = { status: "OFFLINE", all_ok: false };
    allContainersOk = false;
    continue;
  }

  const expected = expectedContainers[host];
  const active = running[host];
  const details = [];
  let hostOk = true;

  for (const name of expected) {
    if (active[name]) {
      details.push({ name, status: "RUNNING", details: active[name] });
    } else {
      details.push({ name, status: "MISSING" });
      hostOk = false;
      allContainersOk = false;
    }
  }

  containersSummary[host] = {
    status: hostOk ? "ALL_OK" : "MISSING_CONTAINERS",
    all_ok: hostOk,
    details
  };
}

return [{  json: {
    containers: containersSummary,
    all_containers_ok: allContainersOk,
    disk_usage: diskUsage
  }
}];

const stdout = items[0].json.stdout || "";
const data = {};
for (const line of stdout.split("\n")) {
  const index = line.indexOf("=");
  if (index === -1) continue;
  const key = line.slice(0, index).trim();
  const value = line.slice(index + 1).trim();
  data[key] = value;
}

const hasDataBackup = Boolean(data.DATA_BACKUP);
const hasDbBackup = Boolean(data.DB_BACKUP);
const hasHtmlBackup = Boolean(data.HTML_BACKUP);
const successLog = Number(data.SUCCESS_LOG || 0) > 0;

const allGood = hasDataBackup && hasDbBackup && hasHtmlBackup && successLog;

return [{
  json: {
    host: data.HOST || "docker-01",
    date: data.DATE,
    backup_ok: allGood,
    details: {
      data: { file: data.DATA_BACKUP, size: data.DATA_SIZE },
      db: { file: data.DB_BACKUP, size: data.DB_SIZE },
      html: { file: data.HTML_BACKUP, size: data.HTML_SIZE },
      success_message_found: successLog
    }
  }
}];

const stdout = items[0].json.stdout || "";
const data = {};
for (const line of stdout.split("\n")) {
  const index = line.indexOf("=");
  if (index === -1) continue;
  const key = line.slice(0, index).trim();
  const value = line.slice(index + 1).trim();
  data[key] = value;
}

const usbMounted = Number(data.USB_MOUNT || 0) > 0;
const hasLatestBackup = Boolean(data.LATEST_BACKUP);
const backupsLast24h = Number(data.BACKUP_COUNT_24H || 0);

const backupOk = usbMounted && hasLatestBackup && backupsLast24h > 0;

return [{
  json: {
    host: data.HOST || "proxmox",
    date: data.DATE,
    usb_mounted: usbMounted,
    backup_ok: backupOk,
    backups_last_24h: backupsLast24h,
    total_backups: Number(data.TOTAL_BACKUPS || 0),
    latest_backup: data.LATEST_BACKUP,
    latest_backup_time: data.LATEST_BACKUP_TIME,
    usb_usage: data.USB_DISK
  }
}];

const services = $('Aggregate Health Check').item.json;
const hosts = $('Aggregate Host Checks').item.json;
const nextcloudBackup = $('Aggregate Nextcloud Backup').item.json;
const proxmoxBackup = $('Aggregate Proxmox Backup').item.json;

const warningThreshold = 80;
const criticalThreshold = 90;

let highestStatus = "Healthy";
let embedColor = 3066993;

let downServices = [];
for (const s of services.services) {
  if (s.status === "DOWN") {
    downServices.push(s.name);
    highestStatus = "Critical";
    embedColor = 15158332;
  }
}

let missingContainers = [];
for (const [host, info] of Object.entries(hosts.containers)) {
  if (info.status === "OFFLINE") {
    missingContainers.push(`${host} is OFFLINE`);
    highestStatus = "Critical";
    embedColor = 15158332;
  } else if (!info.all_ok) {
    const missing = info.details.filter(d => d.status === "MISSING").map(d => d.name);
    missingContainers.push(`${host}: missing ${missing.join(", ")}`);
    highestStatus = "Critical";
    embedColor = 15158332;
  }
}

let diskWarnings = [];
for (const [host, disk] of Object.entries(hosts.disk_usage)) {
  if (disk === "OFFLINE") {
    diskWarnings.push(`${host} disk check: OFFLINE`);
    highestStatus = "Critical";
    embedColor = 15158332;
  } else if (disk && disk.usage) {
    const usageVal = parseInt(disk.usage.replace("%", ""), 10);
    if (usageVal >= criticalThreshold) {
      diskWarnings.push(`${host} disk is critically full: ${disk.usage} (${disk.used} / ${disk.size})`);
      highestStatus = "Critical";
      embedColor = 15158332;
    } else if (usageVal >= warningThreshold) {
      diskWarnings.push(`${host} disk is nearly full: ${disk.usage} (${disk.used} / ${disk.size})`);
      if (highestStatus !== "Critical") {
        highestStatus = "Warning";
        embedColor = 16776960;
      }
    }
  }
}

let backupStatusText = "";
if (nextcloudBackup.backup_ok) {
  backupStatusText += `✅ **Nextcloud Backup**: Success (DB: ${nextcloudBackup.details.db.size}, Data: ${nextcloudBackup.details.data.size})`;
} else {
  backupStatusText += `🚨 **Nextcloud Backup**: FAILED / Missing components`;
  highestStatus = "Critical";
  embedColor = 15158332;
}

backupStatusText += "\n";
if (proxmoxBackup.usb_mounted) {
  if (proxmoxBackup.backup_ok) {
    backupStatusText += `✅ **Proxmox Backup**: Success (${proxmoxBackup.backups_last_24h} backups in 24h, ${proxmoxBackup.total_backups} total)`;
  } else {
    backupStatusText += `🚨 **Proxmox Backup**: FAILED / No backup in last 24h`;
    highestStatus = "Critical";
    embedColor = 15158332;
  }
} else {
  backupStatusText += `⚠️ **Proxmox Backup**: INACTIVE (USB Drive not mounted)`;
  if (highestStatus === "Healthy") {
    highestStatus = "Warning";
    embedColor = 16776960;
  }
}

const lines = [];
lines.push(`🕒 **Time**: ${new Date().toLocaleString("en-US", { timeZone: "America/Santo_Domingo" })}`);
lines.push("");

lines.push("🌐 **Services (Web URLs)**");
if (services.all_ok) {
  lines.push("✅ All web services are online and responding.");
} else {
  lines.push(`🚨 **Down**: ${downServices.join(", ")}`);
}
lines.push("");

lines.push("🐳 **Docker Containers**");
if (hosts.all_containers_ok) {
  lines.push("✅ All expected containers are running healthy.");
} else {
  lines.push(`🚨 **Missing**: ${missingContainers.join("; ")}`);
}
lines.push("");

lines.push("💾 **Disk Usage**");
for (const [host, disk] of Object.entries(hosts.disk_usage)) {
  if (disk === "OFFLINE") {
    lines.push(`🚨 **${host}**: OFFLINE`);
  } else if (disk && disk.usage) {
    lines.push(`- **${host}**: ${disk.usage} (${disk.used} / ${disk.size}) — ${disk.available} avail`);
  } else {
    lines.push(`🚨 **${host}**: Unknown status`);
  }
}
if (diskWarnings.length > 0) {
  lines.push(`\n⚠️ **Warnings**: ${diskWarnings.join("; ")}`);
}
lines.push("");

lines.push("🗄️ **Backups Status**");
lines.push(backupStatusText);

let embedTitle = "";
if (highestStatus === "Healthy") {
  embedTitle = "🟢 YZEE Labs - Daily Health Report (All Systems Nominal)";
} else if (highestStatus === "Warning") {
  embedTitle = "⚠️ YZEE Labs - Daily Health Report (System Warning)";
} else {
  embedTitle = "🔴 YZEE Labs - Daily Health Report (Attention Required)";
}

return [{
  json: {
    username: "Homelab Reporter",
    embeds: [{
      title: embedTitle,
      description: lines.join("\n"),
      color: embedColor,
      footer: {
        text: "YZEE Labs Control Plane | n8n Automation Engine"
      }
    }]
  }
}];
